onClick:
{{
  (function() {

    if (!inp_site_address1.text) {
      showAlert('Address line 1 is required', 'warning');
      return;
    }

    if (!inp_site_city.text) {
      showAlert('City is required', 'warning');
      return;
    }

    if (!inp_site_postcode.text) {
      showAlert('Postcode is required', 'warning');
      return;
    }

    qry_site_create.run(
      function() {
        qry_customer_sites_get.run();
        closeModal('modal_add_site');
        showAlert('Site added successfully', 'success');
        resetWidget('inp_site_address1');
        resetWidget('inp_site_address2');
        resetWidget('inp_site_city');
        resetWidget('inp_site_postcode');
        resetWidget('inp_site_contact');
        resetWidget('inp_site_phone');
        resetWidget('inp_site_email');
      },
      function() {
        showAlert('Failed to add site — please try again', 'error');
      }
    );

  })()
}}
